    double dot = 0.0, magE = 0.0, magB = 0.0;
    size_t size = std::min(exec_vec.size(), book_vec.size());
    for (size_t i = 0; i < size; ++i) {
        dot += std::abs(std::conj(exec_vec[i]) * book_vec[i]);
        magE += std::abs(exec_vec[i] * exec_vec[i]);
        magB += std::abs(book_vec[i] * book_vec[i]);
