double Calculate_Volatility_Entropy(const std::vector<std::complex<double>>& state) {
    if (state.empty()) return 0.0;
    double H = 0.0;
    double total_prob = 0.0;
    for (const auto& amp : state) total_prob += std::abs(amp * amp);
    if (total_prob < 1e-9) return 0.0;
    for (const auto& amp : state) {
        double p = std::abs(amp * amp) / total_prob;
        if (p > 1e-9) H -= p * std::log(p);
