                phi_gains.push_back(-1.0);
                cod_values.push_back(0.0);
                psi_int_finals.push_back(0.0);
                exposure_reductions.push_back(0.0);
            }
        }

        // DYNAMIC AGGREGATION (No Hardcoded Values)
        result.baseline_cod = std::accumulate(baseline_cod_values.begin(), baseline_cod_values.end(), 0.0) / baseline_cod_values.size();
        result.final_cod = std::accumulate(cod_values.begin(), cod_values.end(), 0.0) / cod_values.size();
        result.psi_int_final = std::accumulate(psi_int_finals.begin(), psi_int_finals.end(), 0.0) / psi_int_finals.size();
        result.phi_net_gain = std::accumulate(phi_gains.begin(), phi_gains.end(), 0.0) / phi_gains.size();
        result.exposure_reduction = std::accumulate(exposure_reductions.begin(), exposure_reductions.end(), 0.0) / exposure_reductions.size();

        // False Positive Check
