    // Correlation length scales with: density gradient, collisionality, beta, shear
    constexpr static double DENSITY_GRADIENT_EXPONENT = 0.5;
    constexpr static double BETA_EXPONENT = 0.3;
    constexpr static double SHEAR_EXPONENT = 0.7;

    // Normalize correlation length to [0,1]
    double Calculate_Correlation_Length(
        double density_gradient,    // Normalized [0,1]
        double collisionality,      // Normalized [0,1]
        double beta_parameter,      // Normalized [0,1]
        double shear_flow           // Normalized [0,1]
