        double gradient_factor = std::pow(density_gradient, DENSITY_GRADIENT_EXPONENT);
        double beta_factor = std::pow(beta_parameter, BETA_EXPONENT);
        double shear_factor = std::pow(shear_flow, SHEAR_EXPONENT);

        // Collisionality reduces correlation (turbulence damping)
        double collisionality_damping = std::exp(-0.5 * collisionality);

        double raw_correlation = gradient_factor * beta_factor * 
                                 shear_factor * collisionality_damping;

        // Normalize to [0,1] - DIMENSIONAL COMPLIANCE
        return std::clamp(raw_correlation, 0.0, 1.0);
    }

    // Detect L-H transition proximity (bifurcation point)
    double Calculate_LH_Proximity(double correlation_length, double shear_flow) {
