constexpr double LAMBDA_COUPLING = 0.5;
constexpr double KAPPA_CONFINEMENT = 0.5;
constexpr double ETA_TENSOR_LEAK = 0.3;
constexpr double MU_CORRELATION = 0.4; // Correlation weight in COD

double Calculate_COD_Correlation(
    const std::vector<std::complex<double>>& diagnostic_vec,
    const std::vector<std::complex<double>>& plasma_vec,
    double h_instability,
    double xi_confinement,
    double theta_tensor_leak,
    double correlation_length_parallel,
    double correlation_length_perp
) {
    // 1. Fidelity: Diagnostic-Plasma Alignment Accuracy
    double dot = 0.0, magD = 0.0, magP = 0.0;
    size_t size = std::min(diagnostic_vec.size(), plasma_vec.size());
    for (size_t i = 0; i < size; ++i) {
        dot += std::abs(std::conj(diagnostic_vec[i]) * plasma_vec[i]);
        magD += std::abs(diagnostic_vec[i] * diagnostic_vec[i]);
        magP += std::abs(plasma_vec[i] * plasma_vec[i]);
    }
    double fidelity = 0.0;
    if (magD > 1e-9 && magP > 1e-9) {
        fidelity = dot / (std::sqrt(magD) * std::sqrt(magP));
        fidelity = std::clamp(fidelity, 0.0, 1.0);
    }

    // 2. Root-Aligned COD Formula (with correlation extension)
    double instability_penalty = std::exp(-LAMBDA_COUPLING * h_instability);
    double confinement_penalty = std::exp(-KAPPA_CONFINEMENT * xi_confinement);
    double exposure_penalty = std::exp(-ETA_TENSOR_LEAK * theta_tensor_leak);

    // 3. Correlation Penalty (NEW: ArXiv research integration)
    // Both parallel and perpendicular correlations must be sufficient
    double correlation_mean = (correlation_length_parallel + correlation_length_perp) / 2.0;
    double correlation_penalty = std::exp(-MU_CORRELATION * (1.0 - correlation_mean));

    return fidelity * instability_penalty * confinement_penalty * 
           exposure_penalty * correlation_penalty;
}

