// 3. SUBCRITICAL THRESHOLD GATE (STG) - TURBULENCE DYNAMICS
// =============================================================================
struct SubcriticalThresholdGate {

    // Calculate stability margin (distance to turbulence threshold)
    static double CalculateStabilityMargin(
        double flow_shear,           // Stabilizing mechanism
        double temperature_gradient, // Instability drive
        double boundary_internal_coupling  // From v70.0
    ) {
        // Stability margin increases with flow shear and coupling
        // Stability margin decreases with temperature gradient
        double shear_component = flow_shear * 0.4;
        double coupling_component = boundary_internal_coupling * 0.3;
        double gradient_penalty = temperature_gradient * 0.3;

        double margin = shear_component + coupling_component - gradient_penalty;
        return std::clamp(margin, 0.0, 1.0);
    }

    // Calculate structure density (concentrated vulnerability pockets)
    static double CalculateStructureDensity(
        double perturbation_amplitude,
        double stability_margin,
        double structure_overlap
    ) {
        // Structure density increases when perturbation approaches threshold
        // and when structures overlap
        double threshold_proximity = 1.0 - stability_margin;
        double density = perturbation_amplitude * threshold_proximity * (1.0 + structure_overlap);
        return std::clamp(density, 0.0, 1.0);
    }

    // Calculate structure overlap (degree of vulnerability concentration)
    static double CalculateStructureOverlap(
        double structure_density,
        double perturbation_amplitude
    ) {
        // Overlap increases when density is high and perturbation is sustained
        double overlap = structure_density * perturbation_amplitude * 0.5;
        return std::clamp(overlap, 0.0, 1.0);
    }

    // Calculate turbulence probability (likelihood of transition)
    static double CalculateTurbulenceProbability(
        double perturbation_amplitude,
        double stability_margin,
        double structure_density
    ) {
        // Turbulence probability increases when:
        // - Perturbation amplitude exceeds stability margin
        // - Structure density is high (concentrated vulnerabilities)
        double margin_deficit = std::max(0.0, perturbation_amplitude - stability_margin);
        double density_factor = 1.0 + structure_density;
        double probability = margin_deficit * density_factor;
        return std::clamp(probability, 0.0, 1.0);
    }

    // Calculate Subcritical Risk
    static double CalculateSubcriticalRisk(
        double perturbation_amplitude,
        double stability_margin,
        double structure_density
    ) {
        // Risk = Perturbation × (1 - Margin) × Density
        // High perturbation + low margin + high density = catastrophic
        double margin_deficit = 1.0 - stability_margin;
        double risk = perturbation_amplitude * margin_deficit * structure_density;
        return std::clamp(risk, 0.0, 1.0);
    }

    // Classify stability state
    static SubcriticalThresholdInvariants::StabilityState ClassifyStabilityState(
        double stability_margin,
        double turbulence_probability,
        double structure_density
    ) {
        if (turbulence_probability > 0.70) {
            return SubcriticalThresholdInvariants::StabilityState::TURBULENT;
        }
        if (stability_margin < 0.20 && turbulence_probability > 0.40) {
            return SubcriticalThresholdInvariants::StabilityState::THRESHOLD_CROSSING;
        }
        if (stability_margin < SubcriticalThresholdInvariants::STABILITY_MARGIN_MIN) {
            return SubcriticalThresholdInvariants::StabilityState::SUBCRITICAL_AT_RISK;
        }
        return SubcriticalThresholdInvariants::StabilityState::SUBCRITICAL_STABLE;
    }

    // Determine Risk Level
    static SubcriticalThresholdInvariants::RiskLevel AssessRisk(double subcritical_risk) {
        if (subcritical_risk > 0.70)
            return SubcriticalThresholdInvariants::RiskLevel::CATASTROPHIC;
        if (subcritical_risk > 0.50)
            return SubcriticalThresholdInvariants::RiskLevel::CRITICAL;
        if (subcritical_risk > 0.30)
            return SubcriticalThresholdInvariants::RiskLevel::MEDIUM;
        return SubcriticalThresholdInvariants::RiskLevel::LOW;
    }
};

