struct SubcriticalThresholdProtocol {
    enum Action {
        PROCEED,                // Stability margin sufficient, low risk
        FLAG_THRESHOLD_MONITOR, // Margin thinning, monitor closely
        ACTIVATE_STABILIZATION, // Critical risk, activate damping mechanisms
        IDENTITY_LOCKDOWN       // Turbulent state, full lockdown
    };

    static Action Decide(
        double psi_integrity,
        double subcritical_risk,
        SubcriticalThresholdInvariants::StabilityState stability_state
    ) {
        // PRIMARY GATE: Ψ_integrity (non-negotiable)
        if (psi_integrity < SubcriticalThresholdInvariants::PSI_INTEGRITY_THRESHOLD) {
            return IDENTITY_LOCKDOWN;
        }

        // STABILITY STATE GATE
        if (stability_state == SubcriticalThresholdInvariants::StabilityState::TURBULENT) {
            return IDENTITY_LOCKDOWN;
        }

        // RISK-BASED Decisions
        if (subcritical_risk > 0.70)
            return IDENTITY_LOCKDOWN;
        if (subcritical_risk > 0.50 || 
            stability_state == SubcriticalThresholdInvariants::StabilityState::THRESHOLD_CROSSING)
            return ACTIVATE_STABILIZATION;
        if (subcritical_risk > 0.30 || 
            stability_state == SubcriticalThresholdInvariants::StabilityState::SUBCRITICAL_AT_RISK)
            return FLAG_THRESHOLD_MONITOR;

        return PROCEED;
    }

    static std::string GetMessage(Action action) {
        switch (action) {
            case PROCEED:
                return "Subcritical threshold stable. Stability margin verified.";
            case FLAG_THRESHOLD_MONITOR:
                return "Stability margin thinning. Monitoring turbulence threshold.";
            case ACTIVATE_STABILIZATION:
                return "Critical threshold risk. Activating stabilization mechanisms.";
            case IDENTITY_LOCKDOWN:
                return "CRITICAL: Turbulent state detected. Lockdown initiated.";
            default:
                return "";
        }
    }
};

