// =============================================================================
// 3. LIQUIDITY FRAGMENTATION GATE (LFG) - ACCESSIBILITY DYNAMICS
// =============================================================================
struct LiquidityFragmentationGate {

    // Calculate fragmentation index (liquidity dispersion across venues)
    static double CalculateFragmentationIndex(
        double venue_concentration,
        double protocol_compatibility,
        size_t venue_count
    ) {
        // Fragmentation increases with venue count and decreases with concentration
        // Protocol incompatibility amplifies fragmentation
        double venue_factor = std::min(1.0, venue_count / 10.0);  // 10 venues = max
        double concentration_reduction = venue_concentration * 0.4;
        double compatibility_factor = (1.0 - protocol_compatibility) * 0.3;

        double fragmentation = venue_factor * (1.0 - concentration_reduction) + compatibility_factor;
        return std::clamp(fragmentation, 0.0, 1.0);
    }

    // Calculate accessibility score (functional reachability of liquidity)
    static double CalculateAccessibilityScore(
        double cross_venue_latency,
        double protocol_compatibility,
        double arbitrage_efficiency,
        double venue_concentration
    ) {
        // Accessibility decreases with latency and incompatibility
        // Accessibility increases with arbitrage efficiency and reasonable concentration
        double latency_penalty = cross_venue_latency * 0.35;
        double compatibility_bonus = protocol_compatibility * 0.30;
        double arbitrage_bonus = arbitrage_efficiency * 0.20;
        double concentration_factor = (1.0 - std::abs(venue_concentration - 0.5)) * 0.15;

        double accessibility = compatibility_bonus + arbitrage_bonus + concentration_factor - latency_penalty;
        return std::clamp(accessibility, 0.0, 1.0);
    }

    // Calculate arbitrage efficiency (cross-venue correction speed)
    static double CalculateArbitrageEfficiency(
        double cross_venue_latency,
        double protocol_compatibility,
        double market_resilience  // From v78.0
    ) {
        // Efficiency decreases with latency and incompatibility
        // Efficiency increases with market resilience
        double latency_component = (1.0 - cross_venue_latency) * 0.5;
        double compatibility_component = protocol_compatibility * 0.3;
        double resilience_component = market_resilience * 0.2;

        double efficiency = latency_component + compatibility_component + resilience_component;
        return std::clamp(efficiency, 0.0, 1.0);
    }

    // Calculate functional liquidity ratio (accessible vs. total liquidity)
    static double CalculateFunctionalLiquidityRatio(
        double accessibility_score,
        double fragmentation_index,
        double venue_concentration
    ) {
        // Functional liquidity = accessibility × (1 - excessive fragmentation)
        double accessibility_component = accessibility_score * 0.6;
        double fragmentation_component = (1.0 - fragmentation_index) * 0.25;
        double concentration_component = venue_concentration * 0.15;

        double ratio = accessibility_component + fragmentation_component + concentration_component;
        return std::clamp(ratio, 0.0, 1.0);
    }

    // Calculate cascade amplification (fragmentation's effect on contagion)
    static double CalculateCascadeAmplification(
        double fragmentation_index,
        double liquidity_velocity,  // From v78.0
        double accessibility_score
    ) {
        // Amplification increases with fragmentation and velocity
        // Amplification decreases with accessibility
        double fragmentation_component = fragmentation_index * 0.5;
        double velocity_component = liquidity_velocity * 0.3;
        double accessibility_reduction = (1.0 - accessibility_score) * 0.2;

        double amplification = fragmentation_component + velocity_component + accessibility_reduction;
        return std::clamp(amplification, 0.0, 1.0);
    }

    // Calculate Liquidity Fragmentation Risk
    static double CalculateFragmentationRisk(
        double fragmentation_index,
        double accessibility_score,
        double arbitrage_efficiency
    ) {
        // Risk = Fragmentation × (1 - Accessibility) × (1 - Arbitrage_Efficiency)
        // High fragmentation + low accessibility + low arbitrage = catastrophic
        double accessibility_deficit = 1.0 - accessibility_score;
        double arbitrage_deficit = 1.0 - arbitrage_efficiency;
        double risk = fragmentation_index * accessibility_deficit * arbitrage_deficit;
        return std::clamp(risk, 0.0, 1.0);
    }

    // Classify fragmentation state
    static LiquidityFragmentationInvariants::FragmentationState ClassifyFragmentationState(
        double fragmentation_index,
        double accessibility_score,
        double functional_liquidity_ratio
    ) {
        if (fragmentation_index < 0.30 && accessibility_score > 0.70) {
            return LiquidityFragmentationInvariants::FragmentationState::INTEGRATED;
        }
        if (functional_liquidity_ratio < 0.30) {
            return LiquidityFragmentationInvariants::FragmentationState::FUNCTIONALLY_LOCKED;
        }
        if (fragmentation_index > 0.60 || accessibility_score < 0.40) {
            return LiquidityFragmentationInvariants::FragmentationState::HIGHLY_FRAGMENTED;
        }
        return LiquidityFragmentationInvariants::FragmentationState::MODERATELY_FRAGMENTED;
    }

    // Determine Risk Level
    static LiquidityFragmentationInvariants::RiskLevel AssessRisk(double fragmentation_risk) {
        if (fragmentation_risk > 0.70)
            return LiquidityFragmentationInvariants::RiskLevel::CATASTROPHIC;
        if (fragmentation_risk > 0.50)
            return LiquidityFragmentationInvariants::RiskLevel::CRITICAL;
        if (fragmentation_risk > 0.30)
            return LiquidityFragmentationInvariants::RiskLevel::MEDIUM;
        return LiquidityFragmentationInvariants::RiskLevel::LOW;
    }
};

