// 4. CHAIN OVERLAP DENSITY (COD) — FRAGMENTATION-AWARE
// =============================================================================
constexpr double LAMBDA_COUPLING = 0.5;
constexpr double MU_FRAGMENTATION = 0.7;  // Weight of fragmentation risk in COD

double Calculate_COD_FragmentationAware(
    const std::vector<std::complex<double>>& diagnostic_vec,
    const std::vector<std::complex<double>>& plasma_vec,
    double h_instability,
    double theta_tensor_leak,
    double fragmentation_index,
    double accessibility_score,
    double fragmentation_risk
) {
    // 1. Fidelity (Generic Alignment)
    double dot = 0.0, magD = 0.0, magP = 0.0;
    size_t size = std::min(diagnostic_vec.size(), plasma_vec.size());
    for (size_t i = 0; i < size; ++i) {
        dot += std::abs(std::conj(diagnostic_vec[i]) * plasma_vec[i]);
        magD += std::abs(diagnostic_vec[i] * diagnostic_vec[i]);
        magP += std::abs(plasma_vec[i] * plasma_vec[i]);
    }
    double fidelity = 0.0;
    if (magD > 1e-9 && magP > 1e-9) {
        fidelity = dot / (std::sqrt(magD) * std::sqrt(magP));
        fidelity = std::clamp(fidelity, 0.0, 1.0);
    }

    // 2. Penalties
    double instability_penalty = std::exp(-LAMBDA_COUPLING * h_instability);
    double exposure_penalty = std::exp(-LAMBDA_COUPLING * theta_tensor_leak);

    // 3. Fragmentation Index Penalty (NEW: venue dispersion)
    double fragmentation_penalty = std::exp(-MU_FRAGMENTATION * fragmentation_index);

    // 4. Accessibility Penalty (NEW: functional reachability)
    double accessibility_penalty = std::exp(-MU_FRAGMENTATION * (1.0 - accessibility_score));

    // 5. Fragmentation Risk Penalty
    double risk_penalty = std::exp(-MU_FRAGMENTATION * fragmentation_risk);

    return fidelity * instability_penalty * exposure_penalty * 
           fragmentation_penalty * accessibility_penalty * risk_penalty;
}

