struct LiquidityFragmentationProtocol {
    enum Action {
        PROCEED,            // Fragmentation low, accessibility high
        MONITOR_FRAGMENTATION,  // Moderate fragmentation, monitor closely
        ACTIVATE_BRIDGING,      // Critical risk, activate venue bridging
        IDENTITY_LOCKDOWN       // Functionally locked, full lockdown
    };

    static Action Decide(
        double psi_integrity,
        double fragmentation_risk,
        LiquidityFragmentationInvariants::FragmentationState fragmentation_state
    ) {
        // PRIMARY GATE: Ψ_integrity (non-negotiable)
        if (psi_integrity < LiquidityFragmentationInvariants::PSI_INTEGRITY_THRESHOLD) {
            return IDENTITY_LOCKDOWN;
        }

        // FRAGMENTATION STATE GATE
        if (fragmentation_state == LiquidityFragmentationInvariants::FragmentationState::FUNCTIONALLY_LOCKED) {
            return IDENTITY_LOCKDOWN;
        }

        // RISK-BASED Decisions
        if (fragmentation_risk > 0.70)
            return IDENTITY_LOCKDOWN;
        if (fragmentation_risk > 0.50 || 
            fragmentation_state == LiquidityFragmentationInvariants::FragmentationState::HIGHLY_FRAGMENTED)
            return ACTIVATE_BRIDGING;
        if (fragmentation_risk > 0.30 || 
            fragmentation_state == LiquidityFragmentationInvariants::FragmentationState::MODERATELY_FRAGMENTED)
            return MONITOR_FRAGMENTATION;
        return PROCEED;
    }

    static std::string GetMessage(Action action) {
        switch (action) {
            case PROCEED:
                return "Liquidity fragmentation contained. Accessibility verified.";
            case MONITOR_FRAGMENTATION:
                return "Moderate fragmentation detected. Monitoring venue accessibility.";
            case ACTIVATE_BRIDGING:
                return "Critical fragmentation risk. Activating venue bridging protocols.";
            case IDENTITY_LOCKDOWN:
                return "CRITICAL: Liquidity functionally locked. Lockdown initiated.";
            default:
                return "";
        }
    }
};

