        double verification_component = verification_efficacy * 0.25;
        double anomaly_penalty = (1.0 - anomaly_score) * 0.20;

        double integrity = fidelity_component + preservation_component +
                          verification_component + anomaly_penalty;
        return std::clamp(integrity, 0.0, 1.0);
    }

    // Calculate adversarial surface (fusion manipulation attack vectors)
    static double CalculateAdversarialSurface(
        size_t sensor_count,
        double sensor_compromise_rate,
        double weight_manipulation_risk,
        double mode_injection_risk
    ) {
        // Surface increases with sensor count, compromise rate, and attack risks
        double sensor_factor = std::min(1.0, sensor_count / 20.0); // 20 sensors = max
        double compromise_component = sensor_compromise_rate * 0.40;
        double weight_component = weight_manipulation_risk * 0.30;
        double mode_component = mode_injection_risk * 0.30;

        double surface = sensor_factor * (compromise_component + weight_component + mode_component);
        return std::clamp(surface, 0.0, 1.0);
    }

    // Calculate anomaly score (tampering signal strength)
    static double CalculateAnomalyScore(
        double information_divergence,
        double distribution_fusion_risk,
        double fusion_fidelity
    ) {
        // Anomalies detected via divergence patterns and fidelity inconsistencies
        double divergence_component = information_divergence * 0.50;
        double risk_component = distribution_fusion_risk * 0.30;
        double fidelity_deficit = (1.0 - fusion_fidelity) * 0.20;

        double anomaly = divergence_component + risk_component + fidelity_deficit;
        return std::clamp(anomaly, 0.0, 1.0);
    }

    // Calculate verification efficacy (integrity verification success rate)
    static double CalculateVerificationEfficacy(
        double fusion_integrity_index,
        double adversarial_surface,
        double h_instability
    ) {
        // Efficacy decreases with surface area and instability
        double integrity_component = fusion_integrity_index * 0.50;
        double surface_penalty = (1.0 - adversarial_surface) * 0.30;
        double stability_component = (1.0 - h_instability) * 0.20;

        double efficacy = integrity_component + surface_penalty + stability_component;
        return std::clamp(efficacy, 0.0, 1.0);
    }

    // Calculate weight manipulation risk (weighting scheme attack vulnerability)
    static double CalculateWeightManipulationRisk(
        double sensor_compromise_rate,
        double fusion_fidelity,
        double verification_efficacy
    ) {
        // Risk increases with compromise rate, decreases with fidelity and verification
        double compromise_component = sensor_compromise_rate * 0.50;
        double fidelity_reduction = (1.0 - fusion_fidelity) * 0.30;
        double verification_reduction = (1.0 - verification_efficacy) * 0.20;

        double risk = compromise_component + fidelity_reduction + verification_reduction;
        return std::clamp(risk, 0.0, 1.0);
    }

    // Calculate mode injection risk (false mode insertion vulnerability)
    static double CalculateModeInjectionRisk(
        double mode_preservation,
        double adversarial_surface,
        double anomaly_score
    ) {
        // Risk increases when preservation is low and surface is high
        double preservation_deficit = (1.0 - mode_preservation) * 0.40;
        double surface_component = adversarial_surface * 0.35;
        double anomaly_component = anomaly_score * 0.25;

        double risk = preservation_deficit + surface_component + anomaly_component;
        return std::clamp(risk, 0.0, 1.0);
    }

    // Calculate tampering probability (likelihood of fusion tampering)
    static double CalculateTamperingProbability(
        double adversarial_surface,
        double anomaly_score,
        double verification_efficacy
    ) {
        // Probability increases with surface and anomalies, decreases with verification
        double surface_component = adversarial_surface * 0.40;
        double anomaly_component = anomaly_score * 0.35;
        double verification_deficit = (1.0 - verification_efficacy) * 0.25;

        double probability = surface_component + anomaly_component + verification_deficit;
        return std::clamp(probability, 0.0, 1.0);
    }

    // Calculate Adversarial Fusion Integrity Risk
    static double CalculateIntegrityRisk(
        double integrity_deficit,
        double adversarial_surface,
        double verification_efficacy
    ) {
        // Risk = Integrity_Deficit × Adversarial_Surface × (1 - Verification_Efficacy)
        double verification_deficit = 1.0 - verification_efficacy;
        double risk = integrity_deficit * adversarial_surface * verification_deficit;
        return std::clamp(risk, 0.0, 1.0);
    }

