    double fidelity = 0.0;
    if (magD > 1e-9 && magP > 1e-9) {
        fidelity = dot / (std::sqrt(magD) * std::sqrt(magP));
        fidelity = std::clamp(fidelity, 0.0, 1.0);
    }

    // 2. Penalties
    double instability_penalty = std::exp(-LAMBDA_COUPLING * h_instability);
    double exposure_penalty = std::exp(-LAMBDA_COUPLING * theta_tensor_leak);

    // 3. Homogeneity Penalty (NEW: structural equivalence)
    double homogeneity_penalty = std::exp(-MU_AMM * homogeneity_index);

    // 4. IL Sensitivity Penalty (NEW: fragility metric)
    double il_penalty = std::exp(-MU_AMM * il_sensitivity);

    // 5. AMM Homogeneity Risk Penalty
    double risk_penalty = std::exp(-MU_AMM * amm_homogeneity_risk);

    return fidelity * instability_penalty * exposure_penalty * 
           homogeneity_penalty * il_penalty * risk_penalty;
}

